Total_Fee_Charged_1.query:
q = load "${App.Datasets.RegulatoryTransactionFee_FEN.FullyQualifiedName}";
q = filter q by {{cell(Performance_Over_Per_3.selection, 0, "PeriodStart_Quarter").asEquality("CreatedDate_Quarter")}};
q = filter q by {{cell(MoM_Performance_Over_1.selection, 0, "PeriodStart_Month").asEquality("CreatedDate_Month")}};
q = foreach q generate 'RegulatoryTransactionFeeSource','Status','DueDate','TotalFeeAmount',case when 'Status' == "DUE" and 'DueDate_sec_epoch' < date_to_epoch(now()) then "Overdue Fees" else "Charged Fees" end as 'Fee_Status' ;
result = group q by ('RegulatoryTransactionFeeSource','Fee_Status');
result = foreach result generate q.'RegulatoryTransactionFeeSource' as 'RegulatoryTransactionFeeSource','Fee_Status' as 'Fee_Status', sum(q.'TotalFeeAmount') as 'Amount_Of_Fee_Charged';
result = order result by ('Amount_Of_Fee_Charged' desc);
result = limit result 2000;

