Applications = load "${App.Datasets.Applications_FEN.FullyQualifiedName}";
Applications = filter Applications by {{cell(Performance_Over_Per_3.selection, 0, "PeriodStart_Quarter").asEquality("AppliedDate_Quarter")}};
Applications = filter Applications by {{cell(MoM_Performance_Over_1.selection, 0, "PeriodStart_Month").asEquality("AppliedDate_Month")}};
BusinessLicense = load "${App.Datasets.BusinessLicense_FEN.FullyQualifiedName}";
BusinessLicense = filter BusinessLicense by {{cell(Performance_Over_Per_3.selection, 0, "PeriodStart_Quarter").asEquality("PeriodStart_Quarter")}};
BusinessLicense = filter BusinessLicense by {{cell(MoM_Performance_Over_1.selection, 0, "PeriodStart_Month").asEquality("PeriodStart_Month")}};
---Duration Data
TxnFee_curr = filter TxnFee by {{row(dateSelector_1.selection, [0], ["min", "max"]).asDateRange("date('CreatedDate_Year', 'CreatedDate_Month', 'CreatedDate_Day')")}};
Appl_curr = filter Applications by {{row(dateSelector_1.selection, [0], ["min", "max"]).asDateRange("date('AppliedDate_Year', 'AppliedDate_Month', 'AppliedDate_Day')")}};
Appl_Returned_curr = filter Appl_curr by 'WasReturned' == "true";
License_curr = filter BusinessLicense by {{row(dateSelector_1.selection, [0], ["min", "max"]).asDateRange("date('PeriodStart_Year', 'PeriodStart_Month', 'PeriodStart_Day')")}};
---Compare to Duration
TxnFee_prev = filter TxnFee by {{row(dateSelector_2.selection, [0], ["min", "max"]).asDateRange("date('CreatedDate_Year', 'CreatedDate_Month', 'CreatedDate_Day')")}};
Appl_prev = filter Applications by {{row(dateSelector_2.selection, [0], ["min", "max"]).asDateRange("date('AppliedDate_Year', 'AppliedDate_Month', 'AppliedDate_Day')")}};
Appl_Returned_prev = filter Appl_prev by 'WasReturned' == "true";
License_prev = filter BusinessLicense by {{row(dateSelector_2.selection, [0], ["min", "max"]).asDateRange("date('PeriodStart_Year', 'PeriodStart_Month', 'PeriodStart_Day')")}};
---Cogroup all the streams
result = cogroup TxnFee_curr by all full, Appl_curr by all full, Appl_Returned_curr by all full, License_curr by all full,TxnFee_prev by all full,Appl_prev by all full,Appl_Returned_prev by all full,License_prev by all ;
result = foreach result generate sum(TxnFee_curr.'TotalFeeAmount') as 'Total_Revenue',count(Appl_curr) as 'Total_Applications_Received',count(License_curr) as 'Total_Licenses_Issued',count('Appl_Returned_curr') as 'Total_Applications_Reassigned',sum(TxnFee_prev.'TotalFeeAmount') as 'Total_Revenue_prev',count(Appl_prev) as 'Total_Applications_Received_prev',count(License_prev) as 'Total_Licenses_Issued_prev',count('Appl_Returned_prev') as 'Total_Applications_Reassigned_prev' ;
final = foreach result generate 'Total_Revenue','Total_Applications_Received','Total_Licenses_Issued','Total_Applications_Reassigned','Total_Revenue_prev','Total_Applications_Received_prev','Total_Licenses_Issued_prev','Total_Applications_Reassigned_prev',(('Total_Revenue'- 'Total_Revenue_prev')/'Total_Revenue_prev') as 'perc_Revenue_Change',(('Total_Applications_Received'- 'Total_Applications_Received_prev')/'Total_Applications_Received_prev') as 'perc_Applications_Received_Change',(('Total_Licenses_Issued'- 'Total_Licenses_Issued_prev')/'Total_Licenses_Issued_prev') as 'perc_Licenses_Issued_Change',(('Total_Applications_Reassigned'- 'Total_Applications_Reassigned_prev')/'Total_Applications_Reassigned_prev') as 'perc_Applications_Reassigned_Change';

